import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BZO4qERu.js";const c=JSON.parse('{"title":"日常使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"rudder/02-使用指南/日常使用指南.md","filePath":"rudder/02-使用指南/日常使用指南.md"}'),l={name:"rudder/02-使用指南/日常使用指南.md"};function n(r,a,d,o,p,h){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="日常使用指南" tabindex="-1">日常使用指南 <a class="header-anchor" href="#日常使用指南" aria-label="Permalink to &quot;日常使用指南&quot;">​</a></h1><p>这一章不讲原理，只讲<strong>日常开发中怎么用 Rudder</strong>。</p><h2 id="场景一-开发新功能" tabindex="-1">场景一：开发新功能 <a class="header-anchor" href="#场景一-开发新功能" aria-label="Permalink to &quot;场景一：开发新功能&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：&quot;加个用户登录功能&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_1-ai-自动创建任务" tabindex="-1">1. AI 自动创建任务 <a class="header-anchor" href="#_1-ai-自动创建任务" aria-label="Permalink to &quot;1. AI 自动创建任务&quot;">​</a></h3><p>AI 会先问你几个问题确认需求，然后自动创建任务：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .rudder/scripts/task.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;用户登录功能&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --slug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user-login</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>创建后进入 <strong>Phase 1: Plan</strong>，AI 会：</p><ul><li>和你讨论需求细节</li><li>把结论写入 <code>prd.md</code></li><li>调研需要用到的库和方案</li><li>填充 <code>implement.jsonl</code>（告诉实现代理需要读哪些 Spec）</li></ul><h3 id="_2-激活任务-开始写代码" tabindex="-1">2. 激活任务，开始写代码 <a class="header-anchor" href="#_2-激活任务-开始写代码" aria-label="Permalink to &quot;2. 激活任务，开始写代码&quot;">​</a></h3><p>PRD 完成后，你确认没问题，AI 激活任务：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .rudder/scripts/task.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user-login</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>状态变为 <code>in_progress</code>，进入 <strong>Phase 2: Execute</strong>。AI 会派子代理写代码。</p><h3 id="_3-代码审查" tabindex="-1">3. 代码审查 <a class="header-anchor" href="#_3-代码审查" aria-label="Permalink to &quot;3. 代码审查&quot;">​</a></h3><p>写完代码后，AI 派另一个子代理审查（<code>rudder-check</code>），对照 Spec 逐项检查：</p><ul><li>编码规范是否遵守</li><li>lint、type-check 是否通过</li><li>有没有潜在问题</li></ul><h3 id="_4-沉淀认知-提交代码" tabindex="-1">4. 沉淀认知，提交代码 <a class="header-anchor" href="#_4-沉淀认知-提交代码" aria-label="Permalink to &quot;4. 沉淀认知，提交代码&quot;">​</a></h3><p>审查通过后，进入 <strong>Phase 3: Finish</strong>：</p><ul><li>把本轮学到的新规范写回 Spec（下次就不会忘了）</li><li>AI 展示变更文件，生成提交计划</li><li>你确认后，AI 执行 <code>git commit</code></li><li>提醒你运行 <code>/finish-work</code> 收尾</li></ul><h2 id="场景二-修-bug" tabindex="-1">场景二：修 Bug <a class="header-anchor" href="#场景二-修-bug" aria-label="Permalink to &quot;场景二：修 Bug&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：&quot;登录接口 500 了，查一下&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="简化流程" tabindex="-1">简化流程 <a class="header-anchor" href="#简化流程" aria-label="Permalink to &quot;简化流程&quot;">​</a></h3><p>修 Bug 通常需求很明确，不需要长 PRD：</p><ol><li>AI 创建任务（带简短描述）</li><li>直接进入实现阶段</li><li>修复后审查</li><li>提交代码</li></ol><p>如果 Bug 比较复杂，AI 还是会走完整流程，但 PRD 会很短。</p><h2 id="场景三-代码重构" tabindex="-1">场景三：代码重构 <a class="header-anchor" href="#场景三-代码重构" aria-label="Permalink to &quot;场景三：代码重构&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：&quot;把用户模块的 Controller 拆分成 Service 层&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>重构的特点是：</p><ul><li>PRD 主要是技术方案（改哪些文件、怎么改）</li><li>审查重点是不改行为</li><li>Spec 更新可能比较大（如果重构改变了编码规范）</li></ul><h2 id="场景四-简单修改-跳过流程" tabindex="-1">场景四：简单修改（跳过流程） <a class="header-anchor" href="#场景四-简单修改-跳过流程" aria-label="Permalink to &quot;场景四：简单修改（跳过流程）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：&quot;把这个变量名改一下&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>特别小的修改，你可以说以下任一话术跳过任务流程：</p><ul><li>&quot;skip rudder&quot; / &quot;跳过 rudder&quot; / &quot;别走流程&quot;</li><li>&quot;直接改&quot; / &quot;小修一下&quot;</li><li>&quot;先别建任务&quot;</li></ul><p>AI 看到这些话就会直接改，不创建任务。</p><h2 id="日常开发节奏" tabindex="-1">日常开发节奏 <a class="header-anchor" href="#日常开发节奏" aria-label="Permalink to &quot;日常开发节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>早上：  新需求 → Phase 1 讨论需求 → 确认 PRD</span></span>
<span class="line"><span>上午：  Phase 2 写代码 → Phase 3 审查 + 提交</span></span>
<span class="line"><span>下午：  新需求 → 重复</span></span>
<span class="line"><span>下班前：/finish-work 归档任务，记录工作日志</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="常用操作速查" tabindex="-1">常用操作速查 <a class="header-anchor" href="#常用操作速查" aria-label="Permalink to &quot;常用操作速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你想做什么</th><th>对 AI 说</th></tr></thead><tbody><tr><td>开新需求</td><td>&quot;我想做 XXX&quot;</td></tr><tr><td>修 Bug</td><td>&quot;XXX 出了个问题&quot;</td></tr><tr><td>跳过流程</td><td>&quot;skip rudder&quot; / &quot;跳过 rudder&quot; / &quot;直接改&quot;</td></tr><tr><td>查看当前任务</td><td>&quot;当前在做什么任务？&quot;</td></tr><tr><td>查看工作日志</td><td>&quot;我上次做了什么？&quot;</td></tr><tr><td>更新 Spec</td><td>&quot;这条规则应该写进 Spec&quot;</td></tr><tr><td>结束今天工作</td><td>&quot;/finish-work&quot;</td></tr></tbody></table><h2 id="工具路径管理" tabindex="-1">工具路径管理 <a class="header-anchor" href="#工具路径管理" aria-label="Permalink to &quot;工具路径管理&quot;">​</a></h2><p>第一次遇到工具找不到的情况时：</p><ol><li>AI 会在 session 中显示 <code>&lt;tool-paths&gt;</code> 块，列出所有工具和当前路径</li><li>如果路径不对，你可以： <ul><li>告诉 AI 正确路径</li><li>或者直接编辑 <code>.rudder/config_local.yml</code></li></ul></li><li>AI 会自动把发现的工具追加到 <code>config_local.yml</code></li></ol><blockquote><p>小贴士：<code>config_local.yml</code> 是 git 忽略的，不会被别人覆盖。</p></blockquote>`,42)])])}const b=e(l,[["render",n]]);export{c as __pageData,b as default};
